// Pega o header Authorization enviado pelo React
const authHeader = $input.first().json.headers.authorization;

if (!authHeader) {
  throw new Error('Header Authorization não encontrado');
}

// Remove o prefixo "Bearer " para pegar só o hash
const tokenRecebido = authHeader.replace('Bearer ', '').trim();

try {
  // 1. Decodifica Base64 para String (Simulando a verificação de assinatura)
  // No Node.js do n8n, usamos Buffer em vez de atob()
  const jsonString = Buffer.from(tokenRecebido, 'base64').toString('utf-8');

  // 2. Transforma em Objeto JSON
  const payload = JSON.parse(jsonString);

  // 3. Verifica Expiração (Timestamp atual em segundos vs payload.exp)
  const agora = Math.floor(Date.now() / 1000);

  if (payload.exp < agora) {
    // Se o token venceu, retornamos valid: false
    return {
      json: {
        valid: false,
        message: 'Token expirado'
      }
    };
  }

  // 4. Se chegou aqui, é válido! Retornamos os dados do usuário para o front
  return {
    json: {
      valid: true,
      user: {
        //id: payload.sub,
        email: payload.email,
        name: payload.name
      }
    }
  };

} catch (error) {
  // Se o token for lixo ou mal formatado, cai aqui
  return {
    json: {
      valid: false,
      message: 'Token inválido ou mal formatado'
    }
  };
}

