try {
  // ... Sua lógica de decodificação e validação do token ...
  const jsonString = Buffer.from(tokenRecebido, 'base64').toString('utf-8');
  const payload = JSON.parse(jsonString);
  const agora = Math.floor(Date.now() / 1000);

  let outputJson;

  if (payload.exp < agora) {
    outputJson = {
      valid: false,
      message: 'Token expirado'
    };
  } else {
    outputJson = {
      valid: true,
      user: {
        id: payload.sub,
        email: payload.email,
        name: payload.name
      }
    };
  }

  // --- PARTE CRUCIAL PARA BINÁRIOS ---
  // Cria o objeto de retorno.
  const outputItem = {
    json: outputJson
  };

  // Se o item de entrada possuía dados binários, anexe-os ao item de saída.
  if (inputItem.binary) {
    outputItem.binary = inputItem.binary;
  }
  // ------------------------------------

  return [outputItem]; // Retorna um array contendo o item modificado

} catch (error) {
  // ... Sua lógica de erro ...
  const outputItem = {
    json: {
      valid: false,
      message: 'Token inválido ou mal formatado'
    }
  };

  // No caso de erro, você também pode optar por propagar o binário ou não.
  // Se quiser propagar, adicione a mesma lógica de 'if (inputItem.binary)'.

  return [outputItem];
}

