// Este é um exemplo simplificado para a palestra.
// Ele pega os dados do user e timestamp atual e codifica em Base64 para simular um token.

const payload = {
  sub: $input.first().json.id,
  email: $input.first().json.email,
  name: $input.first().json.name,
  exp: (Date.now() / 1000) + 7200 // Expira em 2 horas
};

// Codifica o payload JSON em uma string Base64 para simular o formato JWT
const tokenSimulado = btoa(JSON.stringify(payload));


return [{ json: { token: tokenSimulado } }];

